mapper.update:
UPDATE TBL_BOARD
   SET VIEW_COUNT = NVL(VIEW_COUNT, 0) + 1
 WHERE BOARD_ID = #{board_id}

mapper.select:
SELECT COUNT(*)
FROM TBL_BOARD_LIKE
WHERE BOARD_ID = #{board_id}
  AND USER_ID = #{user_id}

mapper.update:
UPDATE TBL_BOARD
   SET LIKE_COUNT = NVL(LIKE_COUNT, 0) + 1
 WHERE BOARD_ID = #{board_id}

mapper.select:
SELECT NVL(LIKE_COUNT, 0)
FROM TBL_BOARD
WHERE BOARD_ID = #{board_id}
